<?php
namespace App\Services\Security;use App\Models\{SecurityIncident,SecurityIncidentRecurrenceLink,User};use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class SecurityIncidentRecurrenceService{public function generateRecurrenceKey(SecurityIncident $i):string{$key=Str::slug((string)($i->root_cause_category?:$i->title),'_');$i->update(['recurrence_key'=>$key,'recurrence_status'=>in_array($i->recurrence_status,[null,'unknown'],true)?'first_seen':$i->recurrence_status]);return $key;}public function detectPossibleRecurrences(SecurityIncident $i):array{if(!$i->recurrence_key)$this->generateRecurrenceKey($i);return SecurityIncident::where('id','!=',$i->id)->where('recurrence_key',$i->recurrence_key)->get()->map(fn($x)=>['incident_id'=>$x->id,'incident_number'=>$x->incident_number,'confidence'=>'high','reason'=>'Matching recurrence key.'])->all();}public function linkRecurrence(SecurityIncident $i,SecurityIncident $related,User $a,string $type,string $confidence,string $reason):SecurityIncidentRecurrenceLink{if(!in_array($type,['possible_recurrence','confirmed_recurrence','related_pattern','false_positive'],true))throw ValidationException::withMessages(['relation'=>'Valid recurrence relation is required.']);$l=SecurityIncidentRecurrenceLink::create(['security_incident_id'=>$i->id,'related_incident_id'=>$related->id,'relation_type'=>$type,'confidence'=>$confidence,'reason'=>$reason,'created_by_id'=>$a->id]);$this->event($i,$a,'recurrence_linked',$reason);return $l;}public function confirmRecurrence(SecurityIncidentRecurrenceLink $l,User $a,string $note):SecurityIncidentRecurrenceLink{$l->update(['relation_type'=>'confirmed_recurrence','confirmed_by_id'=>$a->id,'confirmed_at'=>now(),'reason'=>$note]);$i=SecurityIncident::find($l->security_incident_id);$i->update(['recurrence_status'=>'recurring','recurrence_parent_id'=>$l->related_incident_id,'recurrence_detected_at'=>now(),'recurrence_note'=>$note]);$this->event($i,$a,'recurrence_confirmed',$note);return $l->refresh();}public function markFalsePositive(SecurityIncidentRecurrenceLink $l,User $a,string $reason):SecurityIncidentRecurrenceLink{$l->update(['relation_type'=>'false_positive','reason'=>$reason]);$i=SecurityIncident::find($l->security_incident_id);$i->update(['recurrence_status'=>'false_positive','recurrence_note'=>$reason]);$this->event($i,$a,'recurrence_false_positive',$reason);return $l->refresh();}public function getRecurrenceReadiness():array{return ['recurring'=>SecurityIncident::where('recurrence_status','recurring')->count(),'unresolved_possible'=>SecurityIncidentRecurrenceLink::where('relation_type','possible_recurrence')->count()];}private function event($i,$a,$t,$d){$i->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);}}
